<?php $currency=fn($v)=>'Rp '.number_format((float)$v,0,',','.'); $statusMeta=function($s){$s=strtolower((string)$s); if($s==='approved')return['class'=>'success','text'=>'Disetujui','icon'=>'fa-circle-check']; if($s==='rejected')return['class'=>'danger','text'=>'Perlu Perbaikan','icon'=>'fa-circle-xmark']; return['class'=>'warning','text'=>'Menunggu','icon'=>'fa-clock'];}; ?>
<div class="ar-card mb-4"><h2 class="ar-title mb-1">Verifikasi Laporan Dana</h2><p class="ar-subtitle mb-0">Periksa laporan penggunaan dana dari yayasan sebelum dipublikasikan.</p></div>
<div class="ar-card mb-4"><form method="get" action="<?= base_url('admin/report') ?>" class="ar-filter"><input type="text" name="keyword" value="<?= esc($keyword ?? '') ?>" class="form-control" placeholder="Cari laporan, campaign, atau yayasan..."><select name="status" class="form-select"><option value="">Semua Status</option><option value="pending" <?= ($status ?? '')==='pending'?'selected':'' ?>>Menunggu</option><option value="approved" <?= ($status ?? '')==='approved'?'selected':'' ?>>Disetujui</option><option value="rejected" <?= ($status ?? '')==='rejected'?'selected':'' ?>>Perlu Perbaikan</option></select><button class="btn btn-primary rounded-4 fw-bold"><i class="fa-solid fa-magnifying-glass me-2"></i> Filter</button></form></div>
<div class="ar-card"><h4 class="ar-title fs-3 mb-3">Daftar Laporan</h4><?php if(empty($reports)): ?><div class="alert alert-light rounded-4 fw-bold">Belum ada laporan.</div><?php else: ?><table class="ar-table"><thead><tr><th>Laporan</th><th>Yayasan</th><th>Campaign</th><th>Pengeluaran</th><th>Status</th><th>Aksi</th></tr></thead><tbody><?php foreach($reports as $report): ?><?php $m=$statusMeta($report['status_verifikasi'] ?? 'pending'); ?><tr><td data-label="Laporan"><div class="ar-main"><strong><?= esc($report['judul_laporan'] ?? '-') ?></strong><small><?= date('d M Y',strtotime($report['tanggal_laporan'] ?? $report['created_at'] ?? date('Y-m-d'))) ?></small></div></td><td data-label="Yayasan"><?= esc($report['nama_yayasan'] ?? '-') ?></td><td data-label="Campaign"><?= esc($report['campaign_judul'] ?? '-') ?></td><td data-label="Pengeluaran"><strong><?= $currency($report['total_pengeluaran'] ?? 0) ?></strong></td><td data-label="Status"><span class="ar-badge <?= $m['class'] ?>"><i class="fa-solid <?= $m['icon'] ?>"></i> <?= esc($m['text']) ?></span></td><td data-label="Aksi"><a class="ar-btn" href="<?= base_url('admin/report/detail/'.$report['id']) ?>" title="Detail"><i class="fa-solid fa-eye"></i></a></td></tr><?php endforeach; ?></tbody></table><?php if(!empty($pager)): ?><div class="mt-3"><?= $pager->links('admin_reports','default_full') ?></div><?php endif; ?><?php endif; ?></div>
<?= $this->endSection() ?>
